class LogSystem:
    def __init__(self):
        self.logs = []; self.g = {'Year': 4, 'Month': 7, 'Day': 10, 'Hour': 13, 'Minute': 16, 'Second': 19}
    def put(self, id, timestamp): self.logs.append((id, timestamp))
    def retrieve(self, start, end, granularity):
        idx = self.g[granularity]; s, e = start[:idx], end[:idx]
        return [id for id, t in self.logs if s <= t[:idx] <= e]

